// Configure USART1 baud rate register for a given clock
// Assuming USART1 is already enabled and configured for desired mode

// Disable USART1 before configuring BRR
USART1->CR1 &= ~(USART_CR1_UE); // Clear UE bit to disable USART

// Set the desired baud rate and clock source
// Example: 9600 baud with 8 MHz clock, oversampling by 16
// From RM0433 page 2037: USARTDIV = 8000000 / 9600 = 833.33 -> BRR = 0x0341
// For oversampling by 16 (OVER8 = 0), BRR = USARTDIV directly
USART1->BRR = 0x0341; // Set BRR register with calculated value

// Re-enable USART1
USART1->CR1 |= USART_CR1_UE; // Set UE bit to enable USART
```

